parameters.value:
=mutation GrabTOCAndHTMLWithURL {
  goto(url: "{{ $('Set Inputs').item.json.Source }}", waitUntil: networkIdle) {
    status
    url
  }

  pause: waitForTimeout(time: 1500) {
    time
  }

  # Capture the main HTML document response + headers
  documentResponse: response(type: [document], wait: false) {
    url
    status
    headers {
      name
      value
    }
  }

  # Capture JavaScript responses + headers
  scripts: response(type: [script], wait: false) {
    url
    headers {
      name
      value
    }
    body
  }

  finalUrl: url {
    url
  }

  fullHtml: html {
    html
  }
}

assignments.value:
={{
  (() => {
    const html = ($json?.data ?? '').toString?.() ?? '';

    const canonical =
      html.match(/<link[^>]*rel=["']canonical["'][^>]*href=["']([^"']+)["']/i)?.[1] ?? '';

    const finalUrl =
      $json?.data?.finalUrl?.url ?? $json?.finalUrl?.url ?? '';

    const source =
      $('Set Inputs').all?.()?.[0]?.json?.Source ?? '';

    const clean = (v) => String(v ?? '').replace(/[\u0000-\u001F\u007F]/g, '').trim();

    const untouched = clean(finalUrl) || clean(source) || '';
    const canon = clean(canonical);

    const host = (u) => (String(u).match(/^https?:\/\/([^\/?#]+)/i)?.[1] ?? '').toLowerCase();

    return (canon && untouched && host(canon) && host(untouched) && host(canon) !== host(untouched))
      ? canon
      : untouched;
  })()
}}

parameters.jsCode:
// items: [{ json: { data: '...markdown...' } }, ...]

return items.map(item => {
  let md = item.json.data || '';

  // Normalize line endings
  md = md.replace(/\r\n/g, '\n');

  const navJunkPatterns = [
    /you are here:/i,
    /back to top/i,
    /cookie/i,
    /privacy policy/i,
    /terms of (use|service)/i,
    /all rights reserved/i,
    /accept cookies/i,
    /enable javascript/i,
  ];

  const lines = md.split('\n');
  const cleanedLines = [];

  for (let raw of lines) {
    let line = raw;
    const trimmed = line.trim();

    // 1. Keep blank lines (we'll collapse later)
    if (!trimmed) {
      cleanedLines.push('');
      continue;
    }

    // 2. Drop YAML/frontmatter / horizontal rules like "---"
    if (/^---+$/.test(trimmed)) continue;

    // 3. Drop pure punctuation separators (***, ___, etc.)
    if (/^[\-\*_~`]+$/.test(trimmed)) continue;

    // 4. Detect markdown table-ish lines
    const isTableRow = /^\s*\|.*\|\s*$/.test(trimmed);
    const isTableSeparator = /^\s*\|?\s*:?-{2,}.*\|?\s*$/.test(trimmed);

    // If it's clearly a table separator row, drop it
    if (isTableSeparator) continue;

    // Optional: If you want to drop ALL table rows, uncomment:
    // if (isTableRow) continue;

    // 5. Skip obvious nav/footer/legal junk
    if (navJunkPatterns.some(re => re.test(trimmed))) continue;

    // 6. Skip tiny non-heading, non-list UI fragments
    const wordCount = trimmed.split(/\s+/).length;
    const isHeadingOrList = /^(#{1,6}\s|\* |-|\d+\.)/.test(trimmed);
    if (
      wordCount <= 3 &&
      !isHeadingOrList &&
      !/[.!?]$/.test(trimmed) // not a full sentence
    ) {
      // e.g. "Filter:", "Submit Search", "Login"
      continue;
    }

    // 7. Normalize internal spacing a bit
    line = line.replace(/[ \t]{2,}/g, ' ');

    cleanedLines.push(line);
  }

  // 8. Collapse multiple blank lines into a single blank line
  const cleaned = cleanedLines
    .join('\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();

  item.json.cleanedMarkdown = cleaned;
  return item;
});
